    let row = entities::metadata_lock::Entity::find_by_id(key)
        .lock(LockType::Update)
        .one(conn)
        .await
        .map_err(ApiError::internal)?;
    if row.is_none() {
        return Err(ApiError::internal_message(
            "aggregate lock row disappeared during acquisition",
        ));
    }
    Ok(())
}
