   145	async fn refund_open_request_stakes_for_repo_postgres<C>(
   146	    conn: &C,
   147	    repo_id: &str,
   148	    now_unix: u64,
   149	) -> Result<(), ApiError>
   150	where
   151	    C: sea_orm::ConnectionTrait,
   152	{
   153	    let requests = requests_by_repo_id(conn, repo_id).await?;
   154	    for request in requests
   155	        .iter()
   156	        .filter(|request| should_refund_on_repo_delete(request))
   157	    {
   158	        acquire_aggregate_lock(conn, "user-credit", &request.author_user_id).await?;
   159	        let stake_entry = request_stake_debit_entry_for_request_id(conn, &request.id)
   160	            .await?
   161	            .ok_or_else(|| {
   162	                ApiError::internal_message("request stake debit ledger entry is missing")
   163	            })?;
   164	        let ledger_entry_id = repo_delete_refund_ledger_entry_id(&stake_entry.id);
   165	        ensure_repo_delete_refund_ledger_entry_available_postgres(conn, &ledger_entry_id).await?;
   166	        let account = credit_account_by_user_id(conn, &request.author_user_id)
   167	            .await?
   168	            .ok_or_else(|| {
   169	                ApiError::internal_message("request author credit account is missing")
   170	            })?;
   171	        let (account, ledger_entry) =
   172	            refund_open_request_stake(&account, request, ledger_entry_id, now_unix)?;
   173	        save_credit_account_row(conn, &account).await?;
   174	        insert_credit_ledger_entry_row(conn, &ledger_entry).await?;
   175	    }
   176	    Ok(())
   177	}
