    29	impl MetadataStore {
    30	    pub async fn merge_request_with_repository_mutation<R, F>(
    31	        &self,
    32	        owner: &str,
    33	        name: &str,
    34	        input: MergeRequestInput,
    35	        repo_op: F,
    36	    ) -> Result<RequestMergeRepositoryMutation<R>, ApiError>
    37	    where
    38	        R: Send + 'static,
    39	        F: FnOnce(&mut StoredRepository) -> Result<RepositoryMutation<R>, ApiError>
    40	            + Send
    41	            + 'static,
    42	    {
    43	        let repo_id = repo_id(owner, name);
    44	        let owner = owner.to_string();
    45	        let name = name.to_string();
    46	
    47	        let db = Arc::clone(&self.db);
    48	        let tx = db.as_ref().begin().await.map_err(ApiError::internal)?;
    49	        acquire_aggregate_lock(&tx, "repository", &repo_id).await?;
    50	
    51	        let repo = entities::repository::Entity::find_by_id(repo_id)
    52	            .one(&tx)
    53	            .await
    54	            .map_err(ApiError::internal)?
    55	            .ok_or_else(|| ApiError::not_found(format!("repo {owner}/{name} not found")))?;
    56	        let mut repo = repository_from_model(&tx, repo).await?;
    57	        let before_repo = repo.clone();
    58	
    59	        acquire_aggregate_lock(&tx, "request", &input.request_id).await?;
    60	        let request = request_by_id(&tx, &input.request_id)
    61	            .await?
    62	            .ok_or_else(|| ApiError::not_found("request not found"))?;
    63	        if request.repo_id != repo.record.id {
    64	            return Err(ApiError::not_found("request not found"));
    65	        }
    66	        acquire_aggregate_lock(&tx, "user-credit", &request.author_user_id).await?;
    67	        ensure_user_exists(&tx, &input.actor_user_id).await?;
    68	        ensure_request_maintainer(&repo, &input.actor_user_id)?;
    69	
    70	        let mut requests = BTreeMap::from([(request.id.clone(), request.clone())]);
    71	        let mut events = BTreeMap::new();
    72	        for event_id in [&input.event_id, &input.settlement_event_id] {
    73	            if let Some(event) = request_event_by_id(&tx, event_id).await? {
    74	                events.insert(event.id.clone(), event);
    75	            }
    76	        }
    77	        let mut accounts = BTreeMap::new();
    78	        if let Some(account) = credit_account_by_user_id(&tx, &request.author_user_id).await? {
    79	            accounts.insert(account.user_id.clone(), account);
    80	        }
    81	        let mut ledger_entries = BTreeMap::new();
    82	        for entry_id in [
    83	            input.refund_ledger_entry_id.as_deref(),
    84	            input.reward_ledger_entry_id.as_deref(),
    85	        ]
    86	        .into_iter()
    87	        .flatten()
    88	        {
    89	            if let Some(entry) = credit_ledger_entry_by_id(&tx, entry_id).await? {
    90	                ledger_entries.insert(entry.id.clone(), entry);
    91	            }
    92	        }
    93	
    94	        let request_mutation = merge_request(
    95	            &mut requests,
    96	            &mut events,
    97	            &mut accounts,
    98	            &mut ledger_entries,
    99	            input,
   100	        )?;
   101	        let repository_mutation = repo_op(&mut repo)?;
   102	
   103	        save_repository_delta(&tx, &before_repo, &repo).await?;
   104	        save_request_row(&tx, &request_mutation.request).await?;
   105	        insert_request_event_row(&tx, &request_mutation.merged_event).await?;
   106	        insert_request_event_row(&tx, &request_mutation.settled_event).await?;
   107	        if let Some(account) = &request_mutation.account {
   108	            save_credit_account_row(&tx, account).await?;
   109	        }
   110	        for entry in &request_mutation.ledger_entries {
   111	            insert_credit_ledger_entry_row(&tx, entry).await?;
   112	        }
   113	        if !repository_mutation.source_blobs_to_delete.is_empty() {
   114	            queue_pending_source_blob_deletion_rows(
   115	                &tx,
   116	                repository_mutation.source_blobs_to_delete,
   117	            )
   118	            .await?;
   119	        }
   120	        tx.commit().await.map_err(ApiError::internal)?;
   121	        Ok(RequestMergeRepositoryMutation {
   122	            repository_result: repository_mutation.result,
   123	            request: request_mutation,
   124	        })
   125	    }
   126	}
