   256	async fn claim_pending_repo_storage_cleanup_rows<C>(
   257	    conn: &C,
   258	) -> Result<Vec<LoadedRepoStorageCleanup>, ApiError>
   259	where
   260	    C: ConnectionTrait,
   261	{
   262	    let now = u64_to_i64(unix_now()?)?;
   263	    let claim_until = now
   264	        .checked_add(CLEANUP_CLAIM_SECONDS)
   265	        .ok_or_else(|| ApiError::internal_message("cleanup claim time exceeds i64 range"))?;
   266	    let rows = entities::repo_storage_cleanup_job::Model::find_by_statement(
   267	        Statement::from_sql_and_values(
   268	            DatabaseBackend::Postgres,
   269	            r#"
   270	                UPDATE scope_repo_storage_cleanup_jobs AS job
   271	                SET next_run_at_unix = $2, updated_at_unix = $1
   272	                FROM (
   273	                    SELECT repo_id
   274	                    FROM scope_repo_storage_cleanup_jobs
   275	                    WHERE completed_at_unix IS NULL AND next_run_at_unix <= $1
   276	                    ORDER BY next_run_at_unix, repo_id
   277	                    FOR UPDATE SKIP LOCKED
   278	                    LIMIT $3
   279	                ) AS claimed
   280	                WHERE job.repo_id = claimed.repo_id
   281	                RETURNING job.*
   282	            "#,
   283	            [now.into(), claim_until.into(), CLEANUP_BATCH_SIZE.into()],
   284	        ),
   285	    )
   286	    .all(conn)
   287	    .await
   288	    .map_err(ApiError::internal)?;
