   444	async fn reconcile_repo_storage_cleanup_rows<C>(
   445	    conn: &C,
   446	    loaded: &[LoadedRepoStorageCleanup],
   447	    retained: &[RepoStorageCleanup],
   448	    live_repo_ids: &BTreeSet<String>,
   449	) -> Result<(), ApiError>
   450	where
   451	    C: ConnectionTrait,
   452	{
   453	    let retained_repo_ids = retained
   454	        .iter()
   455	        .map(|cleanup| repo_id(&cleanup.owner_handle, &cleanup.repo_name))
   456	        .collect::<BTreeSet<_>>();
   457	    let now_i64 = u64_to_i64(unix_now()?)?;
   458	    for loaded_cleanup in loaded {
   459	        let cleanup = &loaded_cleanup.cleanup;
   460	        let cleanup_repo_id = repo_id(&cleanup.owner_handle, &cleanup.repo_name);
   461	        if retained_repo_ids.contains(&cleanup_repo_id) {
   462	            let last_error = (!live_repo_ids.contains(&cleanup_repo_id))
   463	                .then(|| RETAINED_REPO_STORAGE_ERROR.to_string());
   464	            mark_repo_storage_cleanup_retained(
   465	                conn,
   466	                &cleanup_repo_id,
   467	                &loaded_cleanup.generation,
   468	                last_error,
   469	                now_i64,
   470	            )
   471	            .await?;
   472	        } else {
   473	            complete_pending_repo_storage_cleanup_at(
   474	                conn,
   475	                &cleanup_repo_id,
   476	                &loaded_cleanup.generation,
   477	                now_i64,
   478	            )
   479	            .await?;
   480	        }
   481	    }
   482	    for cleanup in retained {
   483	        if !loaded.iter().any(|loaded| {
   484	            repo_id(&loaded.cleanup.owner_handle, &loaded.cleanup.repo_name)
   485	                == repo_id(&cleanup.owner_handle, &cleanup.repo_name)
   486	        }) {
   487	            queue_pending_repo_storage_cleanup_row(conn, cleanup.clone()).await?;
   488	        }
   489	    }
   490	    Ok(())
   491	}
