   540	pub(crate) async fn drain_pending_repo_storage_deletions_report(
   541	    state: &AppState,
   542	) -> Result<RepoStorageCleanupDrainReport, ApiError> {
   543	    let metadata = state.metadata.clone();
   544	    let state = state.clone();
   545	    let batch = metadata.repo_storage_cleanup_batch().await?;
   546	    let mut report = RepoStorageCleanupDrainReport::default();
   547	    let mut retained = Vec::new();
   548	    for cleanup in &batch.pending {
   549	        if batch
   550	            .live_repo_ids
   551	            .contains(&repo_id(&cleanup.owner_handle, &cleanup.repo_name))
   552	        {
   553	            retained.push(cleanup.clone());
   554	            continue;
   555	        }
   556	        report.attempted += 1;
   557	        match crate::git::storage::delete_repo_storage(
   558	            &state,
   559	            &cleanup.owner_handle,
   560	            &cleanup.repo_name,
   561	        ) {
   562	            Ok(()) => report.deleted += 1,
   563	            Err(error) => {
   564	                tracing::warn!(?error, owner = %cleanup.owner_handle, repo = %cleanup.repo_name, "failed to clean deleted repo filesystem storage");
   565	                report.failed.push(RepoStorageCleanupFailure {
   566	                    owner_handle: cleanup.owner_handle.clone(),
   567	                    repo_name: cleanup.repo_name.clone(),
   568	                    error: error.message,
   569	                });
   570	                retained.push(cleanup.clone());
   571	            }
   572	        }
   573	    }
   574	    report.retained = retained.len();
   575	    metadata
   576	        .finish_repo_storage_cleanup(batch, &retained)
   577	        .await?;
   578	    Ok(report)
