   645	    };
   646	    let delete_report = delete_source_blob_storage(&state, &unreferenced);
   647	    report.deleted = delete_report.deleted_keys.len();
   648	    report.failed_object_deletes = delete_report.failed;
   649	    let retained = unreferenced
   650	        .into_iter()
   651	        .filter(|blob| !delete_report.deleted_keys.contains(&blob.object_key))
   652	        .collect::<Vec<_>>();
   653	    report.retained = retained.len();
   654	    metadata
   655	        .finish_source_blob_cleanup(batch, &retained)
   656	        .await?;
