   166	async fn claim_next_ready_job<C>(
   167	    conn: &C,
   168	    worker_id: &str,
   169	    lease_seconds: i64,
   170	) -> Result<Option<ClaimedOutboxJob>, ApiError>
   171	where
   172	    C: ConnectionTrait + TransactionTrait,
   173	{
   174	    let tx = conn.begin().await.map_err(ApiError::internal)?;
   175	    let now = now_i64()?;
   176	    let runnable = Condition::any()
   177	        .add(
   178	            Condition::all()
   179	                .add(entities::outbox_job::Column::State.eq(JOB_READY))
   180	                .add(entities::outbox_job::Column::NextRunAtUnix.lte(now)),
   181	        )
   182	        .add(
   183	            Condition::all()
   184	                .add(entities::outbox_job::Column::State.eq(JOB_RUNNING))
   185	                .add(entities::outbox_job::Column::LeaseExpiresAtUnix.lte(now)),
   186	        );
   187	
   188	    let Some(job) = entities::outbox_job::Entity::find()
   189	        .filter(entities::outbox_job::Column::CompletedAtUnix.is_null())
   190	        .filter(runnable)
   191	        .order_by_asc(entities::outbox_job::Column::NextRunAtUnix)
   192	        .order_by_asc(entities::outbox_job::Column::CreatedAtUnix)
   193	        .order_by_asc(entities::outbox_job::Column::Id)
   194	        .lock_with_behavior(LockType::Update, LockBehavior::SkipLocked)
   195	        .one(&tx)
   196	        .await
   197	        .map_err(ApiError::internal)?
   198	    else {
   199	        tx.commit().await.map_err(ApiError::internal)?;
   200	        return Ok(None);
   201	    };
   202	
   203	    let claimed = entities::outbox_job::Entity::update_many()
   204	        .filter(entities::outbox_job::Column::Id.eq(job.id.clone()))
   205	        .filter(entities::outbox_job::Column::CompletedAtUnix.is_null())
   206	        .col_expr(
   207	            entities::outbox_job::Column::State,
   208	            Expr::value(JOB_RUNNING),
   209	        )
   210	        .col_expr(
   211	            entities::outbox_job::Column::LeaseOwner,
   212	            Expr::value(Some(worker_id.to_string())),
   213	        )
   214	        .col_expr(
   215	            entities::outbox_job::Column::LeaseExpiresAtUnix,
   216	            Expr::value(Some(now.checked_add(lease_seconds).ok_or_else(|| {
   217	                ApiError::internal_message("outbox lease expiry exceeds i64 range")
   218	            })?)),
   219	        )
   220	        .col_expr(
   221	            entities::outbox_job::Column::UpdatedAtUnix,
   222	            Expr::value(now),
   223	        )
   224	        .exec(&tx)
   225	        .await
   226	        .map_err(ApiError::internal)?;
   227	    if claimed.rows_affected != 1 {
   228	        tx.rollback().await.map_err(ApiError::internal)?;
   229	        return Ok(None);
   230	    }
   231	    tx.commit().await.map_err(ApiError::internal)?;
   232	
   233	    Ok(Some(ClaimedOutboxJob {
   234	        id: job.id,
   235	        kind: job.kind,
   236	        repo_id: job.repo_id,
   237	        repo_version: job.repo_version,
   238	        attempts: job.attempts,
   239	    }))
   240	}
